1	type Item = { type: string; enchantment?: number; cursed?: boolean };
2	type Damage = { itemType: string; amount: number };
3	type Step = {
4	  op: string;
5	  items?: Item[];
6	  policy?: number;
7	  incident?: { cause?: string; damages: Damage[] };
8	};
9	type Scenario = {
10	  customer?: { yearsWithMHPCO?: number };
11	  steps: Step[];
12	};
13	
14	const PROCESSING_FEE = 5;
15	const DEDUCTIBLE_PER_DAMAGE = 100;
16	const CAP_MULTIPLIER = 2;
17	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	const BLOCK_OF_3_PRICE = 60;
34	const BLOCK_ELIGIBLE_TYPES = new Set(["rune", "moonstone"]);
35	const HIGH_ENCHANTMENT_THRESHOLD = 5;
36	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
37	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
38	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const CURSE_SURCHARGE_RATE = 0.5;
40	const LOYALTY_THRESHOLD_YEARS = 2;
41	const LOYALTY_DISCOUNT_RATE = 0.2;
42	const FIRST_INSURANCE_RATE = 0.1;
43	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
44	
45	function quotePremium(
46	  items: Item[],
47	  yearsWithMHPCO: number,
48	  quoteIndex: number,
49	): number {
50	  const countsByType: Record<string, number> = {};
51	  for (const item of items) {
52	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
53	  }
54	  let policyBase = 0;
55	  for (const [type, count] of Object.entries(countsByType)) {
56	    if (BLOCK_ELIGIBLE_TYPES.has(type) && count === 3) {
57	      policyBase += BLOCK_OF_3_PRICE;
58	    } else {
59	      policyBase += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
60	    }
61	  }
62	  let itemSurcharges = 0;
63	  for (const item of items) {
64	    let surchargeRate = 0;
65	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
66	      surchargeRate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
67	    }
68	    if (item.cursed) {
69	      surchargeRate += CURSE_SURCHARGE_RATE;
70	    }
71	    itemSurcharges += surchargeRate * BASE_PREMIUM_BY_ITEM_TYPE[item.type];
72	  }
73	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
74	  const loyaltyDiscount =
75	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
76	  const followUpDiscount = quoteIndex >= 1 ? policyBase * FOLLOW_UP_DISCOUNT_RATE : 0;
77	  return (
78	    Math.ceil(
79	      policyBase + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount,
80	    ) + PROCESSING_FEE
81	  );
82	}
83	
84	function processClaim(
85	  claimStep: Step,
86	  steps: Step[],
87	  remainingCapByPolicy: Record<number, number>,
88	): { payout: number; remainingCap: number } {
89	  const policyIndex = claimStep.policy!;
90	  const policyItems = steps[policyIndex].items ?? [];
91	  if (!(policyIndex in remainingCapByPolicy)) {
92	    const insuranceSum = policyItems.reduce(
93	      (sum, item) => sum + INSURANCE_VALUE_BY_ITEM_TYPE[item.type],
94	      0,
95	    );
96	    remainingCapByPolicy[policyIndex] = CAP_MULTIPLIER * insuranceSum;
97	  }
98	  const damages = claimStep.incident?.damages ?? [];
99	  const grossPayout = damages.reduce((sum, d) => {
100	    const insuredItem = policyItems.find((item) => item.type === d.itemType);
101	    const adjustedAmount =
102	      (insuredItem?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
103	        ? d.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
104	        : d.amount;
105	    return sum + Math.max(0, adjustedAmount - DEDUCTIBLE_PER_DAMAGE);
106	  }, 0);
107	  const payout = Math.min(
108	    Math.floor(grossPayout),
109	    remainingCapByPolicy[policyIndex],
110	  );
111	  remainingCapByPolicy[policyIndex] -= payout;
112	  return { payout, remainingCap: remainingCapByPolicy[policyIndex] };
113	}
114	
115	export function processScenario(scenario: unknown): unknown {
116	  const { customer, steps } = scenario as Scenario;
117	  const yearsWithMHPCO = customer?.yearsWithMHPCO ?? 0;
118	  const remainingCapByPolicy: Record<number, number> = {};
119	  let quoteIndex = 0;
120	  const results = steps.map((step) => {
121	    if (step.op === "claim") {
122	      return processClaim(step, steps, remainingCapByPolicy);
123	    }
124	    const premium = quotePremium(step.items ?? [], yearsWithMHPCO, quoteIndex);
125	    quoteIndex += 1;
126	    return { premium };
127	  });
128	  return { results };
129	}
